mapper.select:
SELECT * FROM foods
AND (LOWER(name_vi) LIKE CONCAT('%', LOWER(#{q}), '%') OR LOWER(name_en) LIKE CONCAT('%', LOWER(#{q}), '%'))
ORDER BY created_at DESC LIMIT #{limit} OFFSET #{offset}

SELECT * FROM ( SELECT p.id, p.title, p.thumbnail, p.adjusted_rating, p.price_range, p.address, p.latitude, p.longitude, (6371000 * acos( LEAST(1.0, GREATEST(-1.0, cos(radians(#{latitude})) * cos(radians(p.latitude::double precision)) * cos(radians(p.longitude::double precision) - radians(#{longitude})) + sin(radians(#{latitude})) * sin(radians(p.latitude::double precision)) )) )) AS distance_meters
) ranked ORDER BY distance_meters ASC NULLS LAST
SELECT p.id, p.title, p.thumbnail, p.adjusted_rating, p.price_range, p.address, p.latitude, p.longitude, NULL::float8 AS distance_meters
ORDER BY p.adjusted_rating DESC NULLS LAST
LIMIT #{limit} OFFSET #{offset}
